UPDATE repair_requests
SET status = #{status},
    reviewer_id = #{reviewerId},
    worker_id = #{workerId}
WHERE id = #{id}

UPDATE repair_requests
SET status = #{status},
    completed_at = #{completedAt}
WHERE id = #{id}

UPDATE repair_requests
SET urge_count = urge_count + 1
WHERE student_id = #{studentId}
  AND id = #{requestId}
  AND status IN ('SUBMITTED', 'ASSIGNED', 'IN_PROGRESS')

UPDATE repair_requests
SET status = #{status}
WHERE student_id = #{studentId}
  AND id = #{requestId}
  AND status IN ('SUBMITTED', 'ASSIGNED')
